#include "oneapi/dal/algo/decision_forest.hpp"
#include "oneapi/dal/io/csv.hpp"

namespace dal = oneapi::dal;
namespace df = dal::decision_forest;

int main() {
    // Load training data and labels
    const auto x_train = dal::read<dal::table>(
        dal::csv::data_source{ "df_classification_train_data.csv" });
    const auto y_train = dal::read<dal::table>(
        dal::csv::data_source{ "df_classification_train_label.csv" });

    // Configure decision forest with detailed parameters
    const auto df_desc = df::descriptor<>{}
        .set_class_count(5)                           // 5 classes
        .set_tree_count(10)                           // 10 trees in forest
        .set_features_per_node(1)                     // Features per split
        .set_min_observations_in_leaf_node(8)         // Min samples in leaf
        .set_min_observations_in_split_node(16)       // Min samples to split
        .set_min_weight_fraction_in_leaf_node(0.0)    // Weight threshold
        .set_min_impurity_decrease_in_split_node(0.0) // Impurity threshold
        .set_variable_importance_mode(df::variable_importance_mode::mdi)
        .set_error_metric_mode(df::error_metric_mode::out_of_bag_error)
        .set_infer_mode(df::infer_mode::class_responses |
                        df::infer_mode::class_probabilities)
        .set_voting_mode(df::voting_mode::weighted);

    // Train the model
    const auto result_train = dal::train(df_desc, x_train, y_train);

    // Access feature importance and training metrics
    std::cout << "Variable importance:\n"
              << result_train.get_var_importance() << std::endl;
    std::cout << "OOB error: " << result_train.get_oob_err() << std::endl;

    // Perform inference on test set
    const auto x_test = dal::read<dal::table>(
        dal::csv::data_source{ "df_classification_test_data.csv" });
    const auto result_infer = dal::infer(df_desc, result_train.get_model(), x_test);

    // Get both class predictions and probabilities
    std::cout << "Predictions:\n" << result_infer.get_responses() << std::endl;
    std::cout << "Probabilities:\n" << result_infer.get_probabilities() << std::endl;

    return 0;
}

#include "oneapi/dal/table/common.hpp"
#include "oneapi/dal/table/homogen.hpp"
#include "oneapi/dal/table/row_accessor.hpp"

namespace dal = oneapi::dal;

template <typename Type = float>
dal::table get_table(std::int64_t row_count, std::int64_t column_count) {
    const std::int64_t elem_count = row_count * column_count;
    auto* const raw_data = new Type[elem_count];

    // Create array with custom deleter
    auto data = dal::array<Type>(raw_data, elem_count,
                                 [](Type* const ptr) -> void {
                                     delete[] ptr;
                                 });

    // Fill with structured data
    for (std::int64_t row = 0l; row < row_count; ++row) {
        for (std::int64_t col = 0l; col < column_count; ++col) {
            const std::int64_t idx = row * column_count + col;
            raw_data[idx] = static_cast<Type>(row * col);
        }
    }

    return dal::homogen_table::wrap(data, row_count, column_count);
}

int main() {
    constexpr std::int64_t row_count = 4;
    constexpr std::int64_t column_count = 3;

    // Create table
    const dal::table test_table = get_table(row_count, column_count);

    // Query table properties
    std::cout << "Rows: " << test_table.get_row_count() << '\n';
    std::cout << "Columns: " << test_table.get_column_count() << '\n';

    // Check table type
    const bool is_homogen = test_table.get_kind() == dal::homogen_table::kind();
    std::cout << "Is homogeneous: " << is_homogen << '\n';

    // Access data using row accessor
    dal::row_accessor<const double> accessor{ test_table };
    dal::array<double> slice = accessor.pull({ 1l, 3l });  // Rows 1-2

    std::cout << "Row slice: " << slice << std::endl;

    return 0;
}

