    // Make predictions on test data
    const auto x_test = dal::read<dal::table>(
        dal::csv::data_source{ "linear_regression_test_data.csv" });
    const auto test_result = dal::infer(lr_desc, x_test, lr_model);

    std::cout << "Predictions:\n" << test_result.get_responses() << std::endl;

