using namespace daal;
using namespace daal::algorithms;

typedef float algorithmFPType;

const size_t nClusters = 20;
const size_t nIterations = 5;
const size_t nBlocks = 4;

int main(int argc, char* argv[]) {
    int rankId, comm_size;
    MPI_Init(&argc, &argv);
    MPI_Comm_size(MPI_COMM_WORLD, &comm_size);
    MPI_Comm_rank(MPI_COMM_WORLD, &rankId);

    // Load local data partition
    NumericTablePtr pData = createSparseTable<float>(
        dataFileNames[rankId]);

    // Initialize centroids in distributed mode
    const size_t nVectorsInBlock = pData->getNumberOfRows();
    kmeans::init::Distributed<step1Local, algorithmFPType,
                             kmeans::init::randomCSR> localInit(
        nClusters,
        nBlocks * nVectorsInBlock,
        rankId * nVectorsInBlock);

    localInit.input.set(kmeans::init::data, pData);
    localInit.compute();

    // Serialize and communicate partial results
    data_management::InputDataArchive dataArch;
    localInit.getPartialResult()->serialize(dataArch);
    size_t perNodeArchLength = dataArch.getSizeOfArchive();

    // Gather data lengths from all nodes
    ByteBuffer serializedData;
    serializedData.resize(perNodeArchLength);
    dataArch.copyArchiveToArray(&serializedData[0], perNodeArchLength);

    // MPI Allgather for collecting partial results
    ByteBuffer nodeResults(perNodeArchLength * nBlocks);
    MPI_Allgather(&serializedData[0], perNodeArchLength, MPI_CHAR,
                  &nodeResults[0], perNodeArchLength, MPI_CHAR,
                  MPI_COMM_WORLD);

    // Master node finalizes initialization
    NumericTablePtr centroids;
    if (rankId == 0) {
        kmeans::init::Distributed<step2Master, algorithmFPType,
                                 kmeans::init::randomCSR> masterInit(nClusters);

        for (size_t i = 0; i < nBlocks; i++) {
            data_management::OutputDataArchive dataArch(
                &nodeResults[perNodeArchLength * i], perNodeArchLength);
            kmeans::init::PartialResultPtr dataForStep2FromStep1(
                new kmeans::init::PartialResult());
            dataForStep2FromStep1->deserialize(dataArch);
            masterInit.input.add(kmeans::init::partialResults,
                                dataForStep2FromStep1);
        }

        masterInit.compute();
        masterInit.finalizeCompute();
        centroids = masterInit.getResult()->get(kmeans::init::centroids);
    }

    // Iterate K-Means computation across nodes
    for (size_t iteration = 0; iteration < nIterations; iteration++) {
        // Each node computes local assignments and updates
        kmeans::Distributed<step1Local> localAlgorithm(nClusters);
        localAlgorithm.input.set(kmeans::data, pData);
        localAlgorithm.input.set(kmeans::inputCentroids, centroids);
        localAlgorithm.compute();

        // Serialize and gather partial results
        // ... (similar MPI communication pattern)

        // Master computes new centroids
        if (rankId == 0) {
            kmeans::Distributed<step2Master> masterAlgorithm(nClusters);
            // Add partial results from all nodes
            // Compute new centroids
            centroids = masterAlgorithm.getResult()->get(kmeans::centroids);
        }

        // Broadcast new centroids to all nodes
        // ... (MPI_Bcast operation)
    }

    if (rankId == 0) {
        printNumericTable(centroids, "Final centroids:", 20, 10);
    }

    MPI_Finalize();
    return 0;
}

